func listItemClass(divided bool) string {
	if divided {
		return "px-6 py-3 border-b border-gray-100 dark:border-gray-700"
	}
	return "px-6 py-3"
}

func listBadgeClass(color string) string {
	base := "inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium "
	switch color {
	case "primary":
		return base + "bg-primary-100 text-primary-700 dark:bg-primary-900/30 dark:text-primary-400"
	case "success", "green":
		return base + "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400"
	case "danger", "red":
		return base + "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
	case "warning", "yellow":
		return base + "bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400"
	case "info", "blue":
		return base + "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400"
	case "purple":
		return base + "bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400"
	default:
		return base + "bg-gray-100 text-gray-600 dark:bg-gray-700 dark:text-gray-400"
	}
}

